var a=function(n){return n*2};var b=function(n){return n+1};var c=function(n){return n-1};var d=function(n){return n*n};var e=function(n){return Math.sqrt(n)};var f=function(n,m){return n+m};var g=function(n,m){return n*m};var h=function(n,m){return n-m};var i=function(arr){return arr.reduce(function(s,x){return s+x},0)};var j=function(arr){return arr.filter(function(x){return x>0})};var k=function(arr){return arr.map(function(x){return x*2})};module.exports={a:a,b:b,c:c,d:d,e:e,f:f,g:g,h:h,i:i,j:j,k:k};
